/* Clear-button slide-in / slide-out animation — shared canonical definition */
@import '../BTInputClear.css';

.bt-input-search {
  display: flex;
  flex-direction: column;
  gap: var(--space-xs);
  width: 100%;
  font-family: var(--typography-font-family-sans);
}

/* The visual field row */
.bt-input-search__field {
  display: flex;
  align-items: center;
  gap: var(--space-sm);
  padding: 12px 8px;
  border: 1px solid var(--border-primary);
  border-radius: var(--radius-sm);
  background: var(--bg-primary);
  transition: border-color 150ms ease;
  box-sizing: border-box;
  width: 100%;
}

.bt-input-search__field--focused {
  border-color: var(--color-brand-primary);
}

.bt-input-search__field--error {
  border-color: var(--text-error);
}

.bt-input-search__field--disabled {
  background: var(--bg-subtle);
  cursor: not-allowed;
}

/* Icon container — controls icon color via 'color' property */
.bt-input-search__icon {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 16px;
  height: 16px;
  flex-shrink: 0;
  color: var(--text-secondary);
}

.bt-input-search__icon--disabled {
  color: var(--text-disabled);
}

/* The actual <input> element */
.bt-input-search__input {
  flex: 1;
  min-width: 0;
  border: none;
  outline: none;
  background: transparent;
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-xs);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  letter-spacing: 0;
  color: var(--text-primary);
  padding: 0;
}

.bt-input-search__input::placeholder {
  color: var(--text-secondary);
}

.bt-input-search__input:disabled {
  color: var(--text-disabled);
  cursor: not-allowed;
}

.bt-input-search__input--error {
  color: var(--text-error);
}

/* Suppress native browser ✕ on type="search" */
.bt-input-search__input[type="search"]::-webkit-search-cancel-button {
  -webkit-appearance: none;
  appearance: none;
}

/* Clear / cancel button — right side, shown when focused + has value */
/* Visibility driven by v-if + <Transition name="bt-input-clear"> — no toggle class needed */
.bt-input-search__cancel {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 16px;
  height: 16px;
  flex-shrink: 0;
  border: none;
  background: none;
  padding: 0;
  cursor: pointer;
  color: var(--icon-primary);
}

/* Validation / helper text row */
.bt-input-search__validation {
  display: flex;
  align-items: center;
  gap: var(--space-xs);
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-xs);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  letter-spacing: 0;
  color: var(--text-secondary);
}

.bt-input-search__validation--error {
  color: var(--text-error);
}

export interface BTInputSearchProps {
  modelValue?: string;
  placeholder?: string;
  disabled?: boolean;
  errorText?: string;
  helperText?: string;
  validator?: (value: string) => string | null;
}
